import { test, expect } from '@playwright/test';
import { fileURLToPath } from 'url';
import path from 'path';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const localUrl = `file://${path.resolve(__dirname, 'target-app/iframe_outer.html')}`;

test('healed test', async ({ page }) => {
  await page.goto(localUrl);
  await expect(page).toHaveTitle('Iframe Outer — AutoHeal Demo');
  await expect(page.locator('iframe')).toHaveCount(1);
  
  const frameLocator = page.frameLocator('iframe[name="inner-frame"]');
  const input = frameLocator.locator('input[placeholder="First name"]');
  
  await input.waitFor({ state: 'visible' });
  await input.fill('John');
  await expect(input).toHaveValue('John');
});
